={
  "model": "gpt-5",
  "messages": [
    { "role": "system", "content": "You are a careful, research-backed parenting writer for NeuroSpark. Cite at least 2 peer-reviewed studies, write 800-1200 words, end with one practical micro-activity, and a single CTA paragraph linking to the app at {{ $env.PUBLIC_APP_WEB_URL }}?utm_source=blog. Output JSON: { title, slug, dek, body_md, tags[] }." },
    { "role": "user", "content": "Topic: {{ $json.topic }}" }
  ],
  "response_format": { "type": "json_object" }
}

parameters.functionCode:
const post = $('Parse JSON').item.json;
const tags = (post.tags || []).slice(0, 4);
const posts = [
  { provider: 'devto',    channelId: $env.POSTIZ_CHANNEL_DEVTO,    content: post.body_md, settings: { __type: 'devto',    title: post.title, tags } },
  { provider: 'medium',   channelId: $env.POSTIZ_CHANNEL_MEDIUM,   content: post.body_md, settings: { __type: 'medium',   title: post.title, tags: tags.slice(0,3).map((t)=>({ value: t, label: t })) } },
  { provider: 'hashnode', channelId: $env.POSTIZ_CHANNEL_HASHNODE, content: post.body_md, settings: { __type: 'hashnode', title: post.title, tags } }
].filter((p) => !!p.channelId);
return [{ json: { posts, tags: ['source:seo_blog_engine'] } }];
